{"file_path":"/home/user/workspace/lib/posts.ts","content":"import { unstable_cache } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  createdAt: Date;
};

// In-memory store (seeded with some initial posts)
const store: Post[] = [
  { id: 1, title: 'Hello World', createdAt: new Date('2024-01-01') },
  { id: 2, title: 'Second Post', createdAt: new Date('2024-01-15') },
];

let nextId = 3;

export function addPost(title: string): Post {
  const post: Post = {
    id: nextId++,
    title,
    createdAt: new Date(),
  };
  store.push(post);
  return post;
}

export const getPosts = unstable_cache(
  async () => {
    // Simulate a data fetch delay to make caching observable
    await new Promise((resolve) => setTimeout(resolve, 200));
    // Return a copy sorted newest-first
    return [...store].reverse();
  },
  ['posts-list'],
  { tags: ['posts'], revalidate: 3600 }
);
"}

{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title')?.toString().trim();

  if (!title || title.length === 0) {
    return { error: 'Title is required' };
  }

  if (title.length > 100) {
    return { error: 'Title must be 100 characters or less' };
  }

  // Persist the new post to the store
  addPost(title);

  // Fully invalidate the 'posts' cache tag.
  // The next request to any fetch/function tagged with 'posts'
  // will re-execute and return fresh data — no stale content is served.
  revalidateTag('posts');

  // Navigate back to the page so the client sees the fresh list
  redirect('/');
}
"}

{"file_path":"/home/user/workspace/app/page.tsx","content":"import { getPosts } from '@/lib/posts';
import { createPost } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost} style={{ marginBottom: '2rem' }}>
        <input
          name="title"
          placeholder="Post title"
          required
          maxLength={100}
          style={{ marginRight: '0.5rem', padding: '0.25rem 0.5rem' }}
        />
        <button type="submit" style={{ padding: '0.25rem 0.75rem' }}>
          Create Post
        </button>
      </form>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul>
          {posts.map((post) => (
            <li key={post.id}>
              <strong>{post.title}</strong>{' '}
              <small>
                ({new Date(post.createdAt).toLocaleDateString()})
              </small>
            </li>
          ))}
        </ul>
      )}

      <p>
        <small>
          Cached with tag &ldquo;posts&rdquo;. Creating a new post invalidates
          the cache via <code>revalidateTag(&apos;posts&apos;)</code>.
        </small>
      </p>
    </main>
  );
}
"}

